export function getExerciseById(id) { return EXERCISE_DB.find(e => e.id === id) || null; }
export function getExerciseByName(name) { return EXERCISE_DB.find(e => e.name.toLowerCase() === name.toLowerCase()) || null; }
export function getExercisesByMuscle(muscle) { return EXERCISE_DB.filter(e => e.primaryMuscle.toLowerCase().includes(muscle.toLowerCase()) || e.secondaryMuscles.some(m => m.toLowerCase().includes(muscle.toLowerCase()))); }
export function getExercisesByEquipment(available) { return EXERCISE_DB.filter(e => e.bodyweight || e.equipment.length === 0 || e.equipment.every(eq => available.includes(eq))); }
export function getSafeExercises(available, injuries = []) { return getExercisesByEquipment(available).filter(e => !e.contraindications.some(c => injuries.includes(c))); }
export function getAllNames() { return EXERCISE_DB.map(e => e.name); }
